}

/* Segmented pill control for view modes */
.segmentedGroup {
  display: flex;
  align-items: center;
  background: var(--color-segment-bg);
  border-radius: var(--radius-md);
  padding: 2px;
  gap: 1px;
  flex-shrink: 0;
}

.segmentedBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 30px;
  padding: 0 10px;
  border-radius: calc(var(--radius-md) - 2px);
  font-size: 11px;
  font-weight: 500;
  color: var(--color-text-secondary);
  background: transparent;
  transition: background var(--duration-fast), color var(--duration-fast), box-shadow var(--duration-fast);
  white-space: nowrap;
  cursor: pointer;
}

.segmentedBtn:hover {
  color: var(--color-text-primary);
  background: rgba(255, 255, 255, 0.05);
}

.segmentedBtnActive {
  composes: segmentedBtn;
  background: var(--color-segment-active-bg);
  color: var(--color-text-primary);
  font-weight: 600;
  box-shadow: var(--color-segment-active-shadow);
}

/* Group label */
.groupLabel {
  font-size: 9px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--color-text-tertiary);
  white-space: nowrap;
  margin-right: 4px;
}

/* Tool palette - inline row */
.toolPalette {
  display: flex;
  align-items: center;
  gap: 1px;
  padding: var(--space-xs) var(--space-sm);
  background: rgba(255, 255, 255, 0.03);
  border-radius: var(--radius-md);
  flex-shrink: 0;
}

.toolPaletteBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 34px;
  height: 34px;
  border-radius: var(--radius-sm);
  border: 1px solid transparent;
  color: var(--color-text-secondary);
  transition: background var(--duration-fast), color var(--duration-fast), border-color var(--duration-fast);
  position: relative;
  cursor: pointer;
}

.toolPaletteBtn:hover {
  background: rgba(255, 255, 255, 0.06);
  border-color: rgba(255, 255, 255, 0.08);
  color: var(--color-text-primary);
}

.toolPaletteBtn:disabled {
  opacity: 0.35;
  cursor: not-allowed;
}

.toolPaletteBtn:disabled:hover {
  background: transparent;
  border-color: transparent;
  color: var(--color-text-secondary);
}

.toolPaletteBtnActive {
  composes: toolPaletteBtn;
  background: var(--color-accent-subtle);
  color: var(--color-accent);
  border-color: rgba(16, 185, 129, 0.20);
  box-shadow: 0 0 8px rgba(16, 185, 129, 0.15);
}

.toolPaletteBtnActive:hover {
  background: rgba(16, 185, 129, 0.18);
}

.toolPaletteIcon {
  width: 18px;
  height: 18px;
  display: block;
}

/* Fixture palette */
.fixturePalette {
  display: flex;
  align-items: center;
  gap: 1px;
  padding: var(--space-xs) var(--space-sm);
  background: rgba(255, 255, 255, 0.03);
  border-radius: var(--radius-md);
  flex-shrink: 0;
}

.fixturePaletteLabel {
  font-size: 9px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--color-text-tertiary);
  margin-right: 4px;
  white-space: nowrap;
}

/* Toggle buttons (sidebar, properties, grid, snap) */
.toggleBtn {
  composes: btn;
  opacity: 0.5;
}

.toggleBtn.toggleActive {
  opacity: 1;
  background: var(--color-accent-subtle);
  color: var(--color-accent);
  border-color: rgba(16, 185, 129, 0.20);
  box-shadow: 0 0 8px rgba(16, 185, 129, 0.12);
}

.spacer {
  flex: 1;
}

/* Responsive breakpoints */
@media (max-width: 1100px) {
  .toolPalette {
    gap: 0;
  }
  .fixturePalette {
    gap: 0;
  }
  .toolPaletteBtn {
    width: 30px;
    height: 30px;
  }
  .segmentedBtn,
  .segmentedBtnActive {
    padding: 0 7px;
    font-size: 10px;
  }
}

@media (max-width: 900px) {
  .toolbar {
    gap: var(--space-xs);
    padding: 0 var(--space-sm);
  }
  .group {
    padding: 0 var(--space-xs);
  }
  .toolPalette {
    padding: 0 var(--space-xs);
  }
  .fixturePalette {
    padding: 0 var(--space-xs);
  }
  .fixturePaletteLabel {
    display: none;
  }
  .groupLabel {
    display: none;
  }
  .segmentedBtn,
  .segmentedBtnActive {
    padding: 0 5px;
    font-size: 10px;
    height: 26px;
  }
}

