  padding: 0 var(--space-md);
  gap: var(--space-sm);
  overflow-x: auto;
  overflow-y: hidden;
  scrollbar-width: thin;
}

.toolbar::-webkit-scrollbar {
  height: 3px;
}
.toolbar::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.10);
  border-radius: 2px;
}
.toolbar::-webkit-scrollbar-track {
  background: transparent;
}

.group {
  display: flex;
  align-items: center;
  gap: 2px;
  padding: var(--space-xs) var(--space-sm);
  background: rgba(255, 255, 255, 0.03);
  border-radius: var(--radius-md);
  flex-shrink: 0;
}

.group + .group {
  border-left: none;
}

.divider {
  width: 1px;
  height: 24px;
  background: rgba(255, 255, 255, 0.08);
  margin: 0 var(--space-xs);
  flex-shrink: 0;
}

/* Icon button base (36x36) */
.btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  padding: 0;
  border-radius: var(--radius-sm);
  border: 1px solid transparent;
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.01em;
  color: var(--color-text-secondary);
  transition: background var(--duration-fast), color var(--duration-fast), border-color var(--duration-fast), transform var(--duration-fast);
  white-space: nowrap;
  position: relative;
}

.btn:hover {
  background: rgba(255, 255, 255, 0.06);
  border-color: rgba(255, 255, 255, 0.08);
  color: var(--color-text-primary);
}

.btn:active {
  transform: scale(0.97);
}

.btn:disabled {
  opacity: 0.35;
  cursor: not-allowed;
}

.btn:disabled:hover {
  background: transparent;
  border-color: transparent;
  color: var(--color-text-secondary);
}

.btn:disabled:active {
  transform: none;
}

.icon {
  width: 18px;
  height: 18px;
  display: block;
}

/* Save with dirty pulsing dot via data attribute */
.saveBtn {
  composes: btn;
}

.saveBtn[data-dirty="true"]::after {
  content: '';
  position: absolute;
  top: 5px;
  right: 5px;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--color-accent);
  box-shadow: 0 0 6px rgba(16, 185, 129, 0.40);
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

/* Segmented pill control for view modes */
.segmentedGroup {
  display: flex;
  align-items: center;
