  background: rgba(255, 255, 255, 0.10);
  border-color: rgba(255, 255, 255, 0.12);
}

.viewportWrap {
  position: relative;
  width: 100%;
  height: 100%;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
}

.viewport {
  width: 100%;
  height: 100%;
  min-height: 0;
}

/* Walk overlay and inspect card stay light for contrast against 3D scene */
.walkOverlay {
  position: absolute;
  left: 16px;
  top: 16px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  max-width: min(320px, calc(100% - 32px));
  padding: 12px 14px;
  border: 1px solid rgba(45, 78, 109, 0.18);
  border-radius: var(--radius-md);
  background: linear-gradient(180deg, rgba(246, 249, 252, 0.95), rgba(236, 242, 247, 0.9));
  box-shadow: 0 12px 28px rgba(37, 48, 61, 0.12);
  pointer-events: none;
}

.walkOverlayTitle {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #35536f;
}

.walkOverlayBody {
  font-size: 12px;
  line-height: 1.5;
  color: #1A1D23;
}

.inspectCard {
  position: absolute;
  top: 16px;
  right: 16px;
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 220px;
  max-width: min(280px, calc(100% - 32px));
  padding: 12px 14px;
  border: 1px solid rgba(15, 143, 116, 0.18);
  border-radius: var(--radius-md);
  background: linear-gradient(180deg, rgba(252, 255, 253, 0.96), rgba(245, 250, 247, 0.92));
  box-shadow: 0 12px 28px rgba(37, 48, 61, 0.14);
  pointer-events: none;
}

.inspectEyebrow {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #5F6470;
}

.inspectTitle {
  font-size: 14px;
  font-weight: 700;
  color: #1A1D23;
}

.inspectMeta {
  font-size: 11px;
  color: #5F6470;
}

.inspectGrid {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 6px;
  margin-top: 6px;
}

.inspectRow {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 12px;
}

.inspectLabel {
  font-size: 11px;
  color: #5F6470;
}

.inspectValue {
  font-size: 12px;
  font-weight: 700;
  color: #1A1D23;
}

.emptyState {
  position: absolute;
  inset: 16px;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  justify-content: flex-end;
  gap: 6px;
  padding: 14px;
  border-radius: var(--radius-md);
  background: linear-gradient(180deg, rgba(30, 32, 40, 0.08), rgba(30, 32, 40, 0.60));
  pointer-events: none;
}

.emptyTitle {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--color-text-secondary);
}

.emptyBody {
  max-width: 220px;
  font-size: 12px;
  line-height: 1.5;
  color: var(--color-text-primary);
}

.footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 10px 14px 12px;
  border-top: 1px solid var(--color-divider);
  font-size: 11px;
  color: var(--color-text-secondary);
  background: linear-gradient(180deg, rgba(30, 32, 40, 0.2), rgba(30, 32, 40, 0.5));
}

.footer span:last-child {
  text-align: right;
}

@media (max-width: 1200px) {
  .panel {
    border-left: none;
    border-top: 1px solid var(--color-border);
  }
}

@media (max-width: 900px) {
  .actions {
    justify-content: flex-start;
  }

  .floorSelect {
    max-width: 100%;
  }
}

